-- CRS pool distribution: top-level + 451-500/401-450 sub-splits.
-- 118 snapshots. Express history 109 dates + PR Tracker 11 dates (2026, real subs).
on conflict (pool_date) do update set
  distribution = excluded.distribution, total = excluded.total,
  source_url = excluded.source_url, fetched_at = excluded.fetched_at;
